#include "wifi_ap.h"
#include <WiFi.h>
void wifi_ap_setup(const char*s,const char*p){WiFi.softAP(s,p);Serial.printf("[wifi_ap] SSID=%s IP=%s\n",s,WiFi.softAPIP().toString().c_str());}
int wifi_ap_client_count(){return WiFi.softAPgetStationNum();}
String wifi_ap_get_ip(){return WiFi.softAPIP().toString();}
